14	// trim whitespace from the beginning and end of a string
15	static std::string trim(const std::string & str) {
16	    size_t start = 0;
17	    size_t end = str.size();
18	    while (start < end && isspace(static_cast<unsigned char>(str[start]))) {
19	        start += 1;
20	    }
21	    while (end > start && isspace(static_cast<unsigned char>(str[end - 1]))) {
22	        end -= 1;
23	    }
24	    return str.substr(start, end - start);
25	}
