747	static void foreach_parameter(const json &                                                         function,
748	                              const std::function<void(const std::string &, const json &, bool)> & fn) {
749	    if (!function.contains("parameters") || !function.at("parameters").is_object()) {
750	        return;
751	    }
752	    const auto & params = function.at("parameters");
753	    if (!params.contains("properties") || !params.at("properties").is_object()) {
754	        return;
755	    }
756	    const auto &          props = params.at("properties");
757	    std::set<std::string> required;
758	    if (params.contains("required") && params.at("required").is_array()) {
759	        params.at("required").get_to(required);
760	    }
761	    for (const auto & [name, prop] : props.items()) {
762	        bool is_required = (required.find(name) != required.end());
763	        fn(name, prop, is_required);
764	    }
765	}
